  1	import { type FC, useMemo, useState } from 'react';
  2	import { Link, useNavigate } from 'react-router-dom-v5-compat';
  3	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
  4	import { PlanStatuses } from 'src/plans/details/components/PlanStatus/utils/types';
  5	import { useForkliftTranslation } from 'src/utils/i18n';
  6	
  7	import { PlanModelRef, type V1beta1ForkliftController } from '@kubev2v/types';
  8	import { ChartDonut } from '@patternfly/react-charts';
  9	import { Card, CardBody, CardTitle } from '@patternfly/react-core';
 10	
 11	import usePlanStatusCounts from '../hooks/usePlanStatusCounts';
 12	import { ChartColors } from '../utils/colors';
 13	import type { ChartDatum } from '../utils/types';
 14	
 15	type MigrationPlansDonutCardProps = {
 16	  obj?: V1beta1ForkliftController;
 17	  loaded?: boolean;
 18	  loadError?: unknown;
 19	};
 20	
 21	const MigrationPlansDonutCard: FC<MigrationPlansDonutCardProps> = () => {
 22	  const { t } = useForkliftTranslation();
 23	  const { count } = usePlanStatusCounts();
 24	  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);
 25	  const navigate = useNavigate();
 26	
 27	  const plansListURL = useMemo(() => {
 28	    return getResourceUrl({
 29	      namespaced: true,
 30	      reference: PlanModelRef,
 31	    });
 32	  }, []);
 33	
 34	  const data =
 35	    count.Total === 0
 36	      ? [{ phase: '', x: 'Empty state', y: 1 }]
 37	      : [
 38	          { phase: PlanStatuses.Archived, x: t('archived'), y: count.Archived },
 39	          { phase: PlanStatuses.Canceled, x: t('canceled'), y: count.Canceled },
 40	          { phase: PlanStatuses.CannotStart, x: t('cannot start'), y: count.CannotStart },
 41	          { phase: PlanStatuses.Completed, x: t('completed'), y: count.Completed },
 42	          { phase: PlanStatuses.Executing, x: t('executing'), y: count.Executing },
 43	          { phase: PlanStatuses.Incomplete, x: t('incomplete'), y: count.Incomplete },
 44	          { phase: PlanStatuses.Paused, x: t('paused'), y: count.Paused },
 45	          { phase: PlanStatuses.Ready, x: t('not started'), y: count.Ready },
 46	          { phase: PlanStatuses.Unknown, x: t('unknown'), y: count.Unknown },
 47	        ];
 48	
 49	  const colorScale =
 50	    count.Total === 0
 51	      ? [ChartColors.Empty]
 52	      : [
 53	          ChartColors.Archived,
 54	          ChartColors.Canceled,
 55	          ChartColors.CannotStart,
 56	          ChartColors.Completed,
 57	          ChartColors.Executing,
 58	          ChartColors.Incomplete,
 59	          ChartColors.Paused,
 60	          ChartColors.NotStarted,
 61	          ChartColors.Unknown,
 62	        ];
 63	
 64	  const highlightColor =
 65	    hoveredIndex !== null && hoveredIndex >= 0 && hoveredIndex < colorScale.length
 66	      ? colorScale[hoveredIndex]
 67	      : ChartColors.Success;
 68	
 69	  return (
 70	    <Card>
 71	      <CardTitle className="forklift-title">{t('Migration plans')}</CardTitle>
 72	      <CardBody className="forklift-overview__status-migration pf-v6-u-display-flex pf-v6-u-align-items-center pf-v6-u-flex-direction-column">
 73	        <div className="forklift-overview__status-migration-donut">
 74	          <ChartDonut
 75	            ariaDesc={t('Donut chart with migration plans statistics')}
 76	            colorScale={colorScale}
 77	            constrainToVisibleArea
 78	            data={data}
 79	            labels={({ datum }: { datum: ChartDatum }) =>
 80	              count.Total === 0
 81	                ? (undefined as unknown as string)
 82	                : `${t('{{count}} plan', { count: datum.y })}
 83	            ${datum.x}`
 84	            }
 85	            title={`${count?.Total ?? '0'}`}
 86	            subTitle={t('Plans')}
 87	            innerRadius={88}
 88	            events={[
 89	              {
 90	                eventHandlers: {
 91	                  onClick: (_, props: { index: number }) => {
 92	                    // Get the phase from the clicked slice
 93	                    const phase = data[props.index]?.phase;
 94	                    // Build the URL with the phase param as a JSON array
 95	                    const params = new URLSearchParams({
 96	                      phase: JSON.stringify([phase]),
 97	                    });
 98	                    navigate(`${plansListURL}?${params.toString()}`);
 99	                    return null;
100	                  },
101	                  onMouseOut: () => {
102	                    setHoveredIndex(null);
103	                    return [
104	                      {
105	                        mutation: () => ({ active: false }),
106	                        target: 'labels',
107	                      },
108	                    ];
109	                  },
110	                  onMouseOver: (_, props: { index: number }) => {
111	                    setHoveredIndex(props.index);
112	                    return [
113	                      {
114	                        mutation: () => ({ active: true }),
115	                        target: 'labels',
116	                      },
117	                    ];
118	                  },
119	                },
120	                target: 'data',
121	              },
122	            ]}
123	            style={{
124	              data: {
125	                cursor: 'pointer',
126	                stroke: ({ index }) => (hoveredIndex === index ? highlightColor : ''),
127	                strokeWidth: ({ index }) => (hoveredIndex === index ? 2 : 1),
128	              },
129	            }}
130	          />
131	        </div>
132	        <div>
133	          <Link to={plansListURL}>{t('View all plans')}</Link>
134	        </div>
135	      </CardBody>
136	    </Card>
137	  );
138	};
139	
140	export default MigrationPlansDonutCard;

